package com.dlock.core.expiration;

import com.dlock.core.model.ReadLockRecord;

/**
 * Expires the lock when createdTime + expirationSeconds > NOW.
 * The NOW is provided by the lock itself (generated by the central repository,
 * e.g. DB).
 */
public class LocalLockExpirationPolicy implements LockExpirationPolicy {

    @Override
    public boolean expired(ReadLockRecord readLockRecord) {
        return readLockRecord.createdTime()
                .plusSeconds(readLockRecord.expirationSeconds())
                .isBefore(readLockRecord.currentTime());
    }

}
